from flask import Flask, session, jsonify, request
from redis import Redis
import functools
import time

app = Flask(__name__)
app.secret_key = 'your_secret_key'
redis_client = Redis(host='localhost', port=6379, db=0)

def cache(expiration=60):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"cache:{func.__name__}:{args}:{kwargs}"
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify({"result": cached_result.decode('utf-8'), "cached": True})
            result = func(*args, **kwargs)
            redis_client.setex(cache_key, expiration, result)
            return jsonify({"result": result, "cached": False})
        return wrapper
    return decorator

@app.route('/set_session/<username>', methods=['POST'])
def set_session(username):
    session['username'] = username
    redis_client.set(f"session:{username}", username)
    return jsonify({"message": "Session set", "username": username})

@app.route('/get_session', methods=['GET'])
def get_session():
    username = session.get('username')
    if username:
        return jsonify({"username": username})
    return jsonify({"message": "No active session"})

